1051	/// (nil/false → true; any other constant → false), flips the condition bit
1052	/// of a jump-result expression, or emits `OP_NOT` for in-register operands.
1053	/// After negation, `e.t` and `e.f` are swapped (the old true-exit list now
1054	/// fires when the negated value is false, and vice versa) and any
1055	/// value-producing tests in the new lists are downgraded to plain tests via
1056	/// `cg_remove_values`.
1057	fn cg_codenot(fs: &mut FuncState, line: i32, e: &mut ExprDesc) -> Result<(), LuaError> {
1058	    match e.k {
1059	        ExprKind::Nil | ExprKind::False => {
1060	            e.k = ExprKind::True;
1061	        }
1062	        ExprKind::K
1063	        | ExprKind::KFlt
1064	        | ExprKind::KInt
1065	        | ExprKind::KStr
1066	        | ExprKind::True => {
1067	            e.k = ExprKind::False;
1068	        }
1069	        ExprKind::Jmp => {
1070	            cg_negate_condition(fs, e);
1071	        }
1072	        ExprKind::Reloc | ExprKind::NonReloc => {
1073	            let reg = cg_exp_to_any_reg(fs, line, e)?;
1074	            cg_free_exp(fs, e);
1075	            let inst = lua_code::opcodes::Instruction::abck(
1076	                lua_code::opcodes::OpCode::Not,
1077	                0,
1078	                reg as u32,
1079	                0,
1080	                0,
1081	            );
1082	            let pc = emit_inst(fs, line, inst);
1083	            e.u.info = pc;
1084	            e.k = ExprKind::Reloc;
1085	        }
1086	        _ => debug_assert!(false, "cg_codenot: unexpected ExprKind {:?}", e.k),
1087	    }
1088	    std::mem::swap(&mut e.f, &mut e.t);
1089	    cg_remove_values(fs, e.f);
1090	    cg_remove_values(fs, e.t);
1091	    Ok(())
1092	}
1093	
1094	/// Emit OP_JMP with NO_JUMP offset; return its pc.
1095	///
1096	/// Mirrors C's `luaK_jump`.
1097	fn cg_jump(fs: &mut FuncState, line: i32) -> i32 {
1098	    let jmp_arg = (NO_JUMP + lua_code::opcodes::OFFSET_S_J) as u32;
1099	    let jmp = lua_code::opcodes::Instruction::sj(
1100	        lua_code::opcodes::OpCode::Jmp,
1101	        jmp_arg,
1102	        0,
1103	    );
1104	    emit_inst(fs, line, jmp)
1105	}
1106	
1107	/// Read an instruction word from `fs.f.code` wrapped in the methodful
1108	/// `lua_code::opcodes::Instruction` so accessor helpers are available.
1109	fn cg_inst_at(fs: &FuncState, pc: i32) -> lua_code::opcodes::Instruction {
1110	    lua_code::opcodes::Instruction(fs.f.code[pc as usize].0)
1111	}
1112	
1113	/// Store an instruction word into `fs.f.code` from a methodful
1114	/// `lua_code::opcodes::Instruction`.
1115	fn cg_set_inst_at(fs: &mut FuncState, pc: i32, inst: lua_code::opcodes::Instruction) {
1116	    fs.f.code[pc as usize] = lua_types::opcode::Instruction::new(inst.0);
1117	}
1118	
1119	/// Return the absolute pc that the jump at `pc` targets, or `NO_JUMP` if the
1120	/// jump's offset field is still the sentinel.
1121	///
1122	/// Mirrors C's `getjump` from `lcode.c`.
1123	fn cg_get_jump(fs: &FuncState, pc: i32) -> i32 {
1124	    let offset = cg_inst_at(fs, pc).arg_s_j();
1125	    if offset == NO_JUMP { NO_JUMP } else { (pc + 1) + offset }
1126	}
1127	
1128	/// Patch the jump at `pc` to land at absolute `dest`.
1129	///
1130	/// Mirrors C's `fixjump` from `lcode.c`.
1131	fn cg_fix_jump(fs: &mut FuncState, pc: i32, dest: i32) -> Result<(), LuaError> {
1132	    debug_assert!(dest != NO_JUMP);
1133	    let offset = dest - (pc + 1);
1134	    let max = lua_code::opcodes::MAXARG_S_J as i32 - lua_code::opcodes::OFFSET_S_J;
1135	    let min = -lua_code::opcodes::OFFSET_S_J;
1136	    if offset < min || offset > max {
1137	        return Err(LuaError::syntax(format_args!("control structure too long")));
1138	    }
1139	    let mut inst = cg_inst_at(fs, pc);
1140	    inst.set_arg_s_j(offset);
1141	    cg_set_inst_at(fs, pc, inst);
1142	    Ok(())
1143	}
1144	
1145	/// Record `fs.pc` as a jump label and return it.
1146	///
1147	/// Mirrors C's `luaK_getlabel` from `lcode.c`.
1148	fn cg_get_label(fs: &mut FuncState) -> i32 {
1149	    fs.lasttarget = fs.pc;
1150	    fs.pc
1151	}
1152	
1153	/// Concatenate jump-list `l2` onto the tail of `*l1`.
1154	///
1155	/// Mirrors C's `luaK_concat` from `lcode.c`.
1156	fn cg_concat(fs: &mut FuncState, l1: &mut i32, l2: i32) -> Result<(), LuaError> {
1157	    if l2 == NO_JUMP { return Ok(()); }
1158	    if *l1 == NO_JUMP { *l1 = l2; return Ok(()); }
1159	    let mut list = *l1;
1160	    loop {
1161	        let next = cg_get_jump(fs, list);
1162	        if next == NO_JUMP { break; }
1163	        list = next;
1164	    }
1165	    cg_fix_jump(fs, list, l2)
1166	}
1167	
1168	/// Patch every jump in the singly-linked list rooted at `list` to land at
1169	/// absolute pc `target`.
1170	///
1171	/// Phase-A subset of C's `luaK_patchlist`: skips the `TestSet`→`Test`
1172	/// rewrite (`patchtestreg`) since `goiftrue`/`goiffalse` here only produce
1173	/// raw comparison-followed-by-jump expressions, not boolean short-circuit
1174	/// chains that need register patching.
1175	fn cg_patch_list(fs: &mut FuncState, list: i32, target: i32) -> Result<(), LuaError> {
1176	    let mut list = list;
1177	    while list != NO_JUMP {
1178	        let next = cg_get_jump(fs, list);
1179	        cg_fix_jump(fs, list, target)?;
1180	        list = next;
1181	    }
1182	    Ok(())
1183	}
1184	
1185	/// Patch every jump in `list` to land at the current `fs.pc`.
1186	///
1187	/// Mirrors C's `luaK_patchtohere` from `lcode.c`.
1188	fn cg_patch_to_here(fs: &mut FuncState, list: i32) -> Result<(), LuaError> {
1189	    let target = cg_get_label(fs);
1190	    cg_patch_list(fs, list, target)
1191	}
1192	
1193	/// Flip the `k` (condition) bit of the test instruction that immediately
1194	/// precedes `e`'s JMP. After this, the jump fires on the opposite truth
1195	/// value of the original comparison.
1196	///
1197	/// Mirrors C's `negatecondition` from `lcode.c`.
1198	fn cg_negate_condition(fs: &mut FuncState, e: &ExprDesc) {
1199	    let pc = e.u.info - 1;
1200	    let mut inst = cg_inst_at(fs, pc);
1201	    let k = inst.arg_k();
1202	    inst.set_arg_k(k ^ 1);
1203	    cg_set_inst_at(fs, pc, inst);
1204	}
1205	
1206	/// Arrange for control to fall through when `e` is true and to jump (via the
1207	/// patch list rooted at `e.f`) when `e` is false. After this call `e.t` has
1208	/// been patched to the current pc and `e.f` holds the false-exit list.
1209	///
1210	/// Mirrors C's `luaK_goiftrue` from `lcode.c`. `VJMP` (comparison results)
1211	/// negate the condition so the jump fires on false; literal-true forms emit
1212	/// no jump; any other kind is forced into a register and tested with
1213	/// `OP_TESTSET` via `cg_jump_on_cond`.
1214	fn cg_go_if_true(fs: &mut FuncState, line: i32, e: &mut ExprDesc) -> Result<(), LuaError> {
1215	    cg_discharge_vars(fs, line, e)?;
1216	    let pc: i32 = match e.k {
1217	        ExprKind::Jmp => {
1218	            cg_negate_condition(fs, e);
1219	            e.u.info
1220	        }
1221	        ExprKind::K | ExprKind::KFlt | ExprKind::KInt | ExprKind::KStr | ExprKind::True => {
1222	            NO_JUMP
1223	        }
1224	        _ => cg_jump_on_cond(fs, line, e, 0)?,
1225	    };
1226	    cg_concat(fs, &mut e.f, pc)?;
1227	    cg_patch_to_here(fs, e.t)?;
1228	    e.t = NO_JUMP;
1229	    Ok(())
1230	}
1231	
1232	/// Mirror of `cg_go_if_true` for false short-circuit (`or` operator and
1233	/// `while not <cond>` shaped control flow). Falls through when `e` is false
1234	/// and jumps when true. After this call `e.f` has been patched to the
1235	/// current pc and `e.t` holds the true-exit list.
1236	///
1237	/// Mirrors C's `luaK_goiffalse` from `lcode.c`.
1238	fn cg_go_if_false(fs: &mut FuncState, line: i32, e: &mut ExprDesc) -> Result<(), LuaError> {
1239	    cg_discharge_vars(fs, line, e)?;
1240	    let pc: i32 = match e.k {
1241	        ExprKind::Jmp => e.u.info,
1242	        ExprKind::Nil | ExprKind::False => NO_JUMP,
1243	        _ => cg_jump_on_cond(fs, line, e, 1)?,
1244	    };
1245	    cg_concat(fs, &mut e.t, pc)?;
1246	    cg_patch_to_here(fs, e.f)?;
1247	    e.f = NO_JUMP;
1248	    Ok(())
1249	}

