1430	/// For a VarArg this patches `ARG_C = 2` and leaves `e` as `Reloc` so the
1431	/// caller can place the single result into a destination register.
1432	fn cg_set_one_ret(fs: &mut FuncState, e: &mut ExprDesc) {
1433	    if e.k == ExprKind::Call {
1434	        let pc_idx = e.u.info as usize;
1435	        let lc = lua_code::opcodes::Instruction(fs.f.code[pc_idx].0);
