/// C: UNARY_PRIORITY 12
const UNARY_PRIORITY: i32 = 12;

/// C: LUA_MULTRET from lua.h
const LUA_MULTRET: i32 = -1;

/// C: MAXUPVAL 255 from lfunc.h
